const body = $json.body || $json;
const evt = body.event || 'unknown';
const actorName = (body.actor && body.actor.name) ? body.actor.name : 'Jemand';
const appUrl = body.app_url || 'https://ludwig-a11y.github.io/halleluja-os/';
const teamChannel = 'C0A7LTX603Z';
const teamIds = body.team_slack_ids || [];

let text = actorName + ': ' + evt;
let targets = [teamChannel];

if (evt === 'aufgabe_gestartet') {
  const prio = body.prio ? ' (' + body.prio + ')' : '';
  text = '▶ *' + actorName + '* hat losgelegt' + prio + ' — <' + appUrl + '|Woran arbeitest du gerade?>';
  if (teamIds.length) targets = teamIds;
} else if (evt === 'aufgabe_erledigt') {
  const prio = body.prio ? ' (' + body.prio + ')' : '';
  text = '✅ *' + actorName + '* hat eine Aufgabe erledigt' + prio + ' — <' + appUrl + '|App öffnen>';
  if (teamIds.length) targets = teamIds;
} else if (evt === 'big3_erledigt') {
  text = '🏅 *' + actorName + '* hat ein Big-3 Ziel erreicht (KW ' + (body.kw || '?') + ') — <' + appUrl + '|App öffnen>';
  if (teamIds.length) targets = teamIds;
} else if (evt === 'aufgabe_zugewiesen') {
  text = '📋 *' + actorName + '* hat dir eine Aufgabe zugewiesen:\n> *' + (body.aufgabe || '?') + '*';
  if (body.prio) text += ' (' + body.prio + ')';
  if (body.dl) text += ' — fällig: ' + body.dl;
  text += '\n<' + appUrl + '|App öffnen>';
  if (body.fuer && body.fuer.slack_id) targets = [body.fuer.slack_id];
} else if (evt === 'meilenstein_erledigt') {
  text = '🎯 *' + actorName + '* hat einen Meilenstein erreicht!\n> ✅ *' + (body.meilenstein || '?') + '*';
  if (teamIds.length) targets = teamIds;
} else if (evt === 'aufgabe_weitergeleitet') {
  text = '↪️ *' + actorName + '* hat deine Aufgabe weitergeleitet:\n> *' + (body.aufgabe || '?') + '*\n> Neuer Zuständiger: *' + (body.weitergeleitet_an || '?') + '*\n<' + appUrl + '|App öffnen>';
  if (body.fuer && body.fuer.slack_id) targets = [body.fuer.slack_id];
} else if (evt === 'diskussion') {
  const typ = body.typ || 'Thema';
  const thema = body.thema || '?';
  const notiz = body.notiz ? '\n> 💬 ' + body.notiz : '';
  const bereich = body.bereich && body.bereich !== 'alle' ? ' (für ' + body.bereich + ')' : '';
  text = '🗣️ *' + actorName + '* möchte besprechen:\n> *' + typ + bereich + ':* ' + thema + notiz + '\n\nBitte hier im Thread diskutieren 👇';
} else if (evt === 'wolke_zurueck') {
  const typ = body.typ || 'Wolke';
  text = '↩ *' + actorName + '* hat deine ' + typ + ' zurückgegeben:\n> *' + (body.thema || '?') + '*\nSie ist jetzt im allgemeinen Pool.\n<' + appUrl + '|App öffnen>';
  if (body.fuer && body.fuer.slack_id) targets = [body.fuer.slack_id];
} else if (evt === 'blocker') {
  text = '⚠️ *' + actorName + '* meldet einen Blocker:\n> ' + (body.blocker || '?');
}

return targets.map(ch => ({ json: { channel: ch, text: text } }));
